MERGE INTO CONSULTAS FIN USING (SELECT '002051StickerTramites' INFORME ,TO_CLOB(q'[SELECT COMPANIA.NOMBRE COMPANIA, TRAMITES.DESCRIPCION , TRAMITES.HORA , TRAMITES.FECHA, TRAMITES.NUMERO BARRAS, 
   TRAMITES.PROCESOS||'-'||TRAMITES.NODO_ACTUAL||'-'||TRAMITES.SERIE_DOCUMENTAL CODIGODEBARRAS_BIN, DEPENDENCIA.NOMBRE AS DEPENDENCIA 
FROM TRAMITES INNER JOIN COMPANIA 
   ON TRAMITES.COMPANIA= COMPANIA.CODIGO 
   INNER JOIN DEPENDENCIA
   ON TRAMITES.COMPANIA = DEPENDENCIA.COMPANIA
   AND TRAMITES.DEPENDENCIA = DEPENDENCIA.CODIGO 
WHERE TRAMITES.COMPANIA = s$compania$s
AND TRAMITES.PROCESOS ='s$procesos$s'
AND TRAMITES.NUMERO=s$numero$s
AND TRAMITES.TIPO_TRAMITE = s$tipotramites$s]') CONSULTA, 35 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);